switch retryResult {
case .doNotRetry:
    didComplete = { completionHandler(response) }

case let .doNotRetryWithError(retryError):
    let result: AFResult<Serializer.SerializedObject> = .failure(retryError.asAFError(orFailWith: "Received retryError was not already AFError"))

    let response = DataResponse(request: self.request,
                                response: self.response,
                                data: self.data,
                                metrics: self.metrics,
                                serializationDuration: end - start,
                                result: result)

    didComplete = { completionHandler(response) }

case .retry, .retryWithDelay:
    delegate.retryRequest(self, withDelay: retryResult.delay)
}

switch retryResult {
case .doNotRetry:
    didComplete = { completionHandler(response) }

case let .doNotRetryWithError(retryError):
    let result: AFResult<Serializer.SerializedObject> = .failure(retryError.asAFError(orFailWith: "Received retryError was not already AFError"))

    let response = DownloadResponse(request: self.request,
                                    response: self.response,
                                    fileURL: self.fileURL,
                                    resumeData: self.resumeData,
                                    metrics: self.metrics,
                                    serializationDuration: end - start,
                                    result: result)

    didComplete = { completionHandler(response) }

case .retry, .retryWithDelay:
    delegate.retryRequest(self, withDelay: retryResult.delay)
}

switch request {
// UploadRequest must come before DataRequest due to subtype relationship.
case let r as UploadRequest: self.performUploadRequest(r)
case let r as DataRequest: self.performDataRequest(r)
case let r as DownloadRequest: self.performDownloadRequest(r)
case let r as DataStreamRequest: self.performDataStreamRequest(r)
default:
    #if canImport(Darwin) && !canImport(FoundationNetworking)
    if #available(macOS 10.15, iOS 13, tvOS 13, watchOS 6, *),
       let request = request as? WebSocketRequest {
        self.performWebSocketRequest(request)
    } else {
        fatalError("Attempted to perform unsupported Request subclass: \(type(of: request))")
    }
    #else
    fatalError("Attempted to perform unsupported Request subclass: \(type(of: request))")
    #endif
}

do {
    if options.contains(.removePreviousFile), fileManager.fileExists(atPath: destination.path) {
        try fileManager.removeItem(at: destination)
    }

    if options.contains(.createIntermediateDirectories) {
        let directory = destination.deletingLastPathComponent()
        try fileManager.createDirectory(at: directory, withIntermediateDirectories: true)
    }

    try fileManager.moveItem(at: location, to: destination)

    request.didFinishDownloading(using: downloadTask, with: .success(destination))
} catch {
    request.didFinishDownloading(using: downloadTask, with: .failure(.downloadedFileMoveFailed(error: error,
                                                                                               source: location,
                                                                                               destination: destination)))
}

if multipartFormData.read(\.contentLength) < encodingMemoryThreshold {
    let data = try multipartFormData.read { try $0.encode() }

    uploadable = .data(data)
} else {
    let tempDirectoryURL = fileManager.temporaryDirectory
    let directoryURL = tempDirectoryURL.appendingPathComponent("org.alamofire.manager/multipart.form.data")
    let fileName = UUID().uuidString
    let fileURL = directoryURL.appendingPathComponent(fileName)

    try fileManager.createDirectory(at: directoryURL, withIntermediateDirectories: true, attributes: nil)

    do {
        try multipartFormData.read { try $0.writeEncodedData(to: fileURL) }
    } catch {
        // Cleanup after attempted write if it fails.
        try? fileManager.removeItem(at: fileURL)
        throw error
    }

    uploadable = .file(fileURL, shouldRemove: true)
}

for argumentDefinition in argumentSet {
  guard case .positional = argumentDefinition.kind else { continue }
  switch argumentDefinition.parsingStrategy {
  case .default, .allRemainingInput:
    break
  default:
    continue ArgumentLoop
  }
  guard case .unary(let update) = argumentDefinition.update else {
    preconditionFailure("Shouldn't see a nullary positional argument.")
  }
  let allowOptionsAsInput =
    argumentDefinition.parsingStrategy == .allRemainingInput

  repeat {
    guard let arg = next(unconditional: allowOptionsAsInput) else {
      break ArgumentLoop
    }
    let origin: InputOrigin.Element = .argumentIndex(arg.index)
    // swift-format-ignore: NeverForceUnwrap
    // FIXME: I dont actually know why this is safe
    let value = unusedInput.originalInput(at: origin)!
    try update([origin], nil, value, &result)
    usedOrigins.insert(origin)
  } while argumentDefinition.isRepeatingPositional
}

if level.isAtRoot, self.hasSingletonItem {
  // In this special case, the root node may turn into a collision node
  // during the merge process. Prevent this from causing issues below by
  // handling it up front.
  var copy = other
  let delta = try self.read { l in
    let lp = l.itemPtr(at: .zero)
    let c = copy.count
    let res = copy.updateValue(
      level, forKey: lp.pointee.key, _Hash(lp.pointee.key)
    ) {
      $0.initialize(to: lp.pointee)
    }
    if !res.inserted {
      try UnsafeHandle.update(res.leaf) {
        let p = $0.itemPtr(at: res.slot)
        p.pointee.value = try combine(lp.pointee.value, p.pointee.value)
      }
    }
    return c - (res.inserted ? 0 : 1)
  }
  self = copy
  return delta
}

if lc {
  // `self` is a collision node on a compressed path. The other tree might
  // have the same set of collisions, just expanded a bit deeper.
  return read { l in
    other.read { r in
      let bucket = l.collisionHash[level]
      if r.itemMap.contains(bucket) {
        let rslot = r.itemMap.slot(of: bucket)
        let ritem = r.itemPtr(at: rslot)
        let h = _Hash(ritem.pointee.key)
        let res = l.find(level, ritem.pointee.key, h)
        guard let res = res else { return nil }
        return self._removingItemFromLeaf(level, at: bucket, res.slot)
          .replacement
      }
      else if r.childMap.contains(bucket) {
        let rslot = r.childMap.slot(of: bucket)
        return _subtracting(level.descend(), r[child: rslot])
          .map { .childBranch(level, $0, at: bucket) }
      }
      return nil
    }
  }
}

while !container.isAtEnd {
  let key = try container.decode(Key.self)
  let (index, bucket) = self._keys._find(key)
  guard index == nil else {
    let context = DecodingError.Context(
      codingPath: container.codingPath,
      debugDescription: "Duplicate key at offset \(container.currentIndex - 1)")
    throw DecodingError.dataCorrupted(context)
  }

  guard !container.isAtEnd else {
    throw DecodingError.dataCorrupted(
      DecodingError.Context(
        codingPath: container.codingPath,
        debugDescription: "Unkeyed container reached end before value in key-value pair"
      )
    )
  }
  let value = try container.decode(Value.self)
  _keys._appendNew(key, in: bucket)
  _values.append(value)
}
